(6, 'Prémium E fonal - Fehér', 'Kiváló minőségű E fonal kézzel készítéshez.', 2755, 148, 159, 6, 18, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(7, 'inventore', 'Quam accusamus voluptas et aut beatae ea alias id modi illum magnam quo ad aliquid non dolore id sit accusantium quia aut officiis dolorem delectus voluptas sed adipisci nesciunt expedita impedit possimus numquam consequatur ipsa placeat a harum sit dignissimos provident autem error modi sed labore unde qui hic cumque deserunt eveniet sequi.', 3681, 232, 4592, 16, 22, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(8, 'minus', 'Mollitia sit similique sint saepe veritatis sed a accusantium necessitatibus dignissimos voluptas itaque optio nam illum quos delectus laborum possimus ut soluta ducimus ut illum qui labore amet dolorum quos delectus molestias labore repellendus iusto sunt nihil reiciendis quia provident soluta nulla dolorum repellat cupiditate pariatur facilis repudiandae et pariatur.', 2491, 300, 4549, 8, 16, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(9, 'dolor', 'Consectetur assumenda placeat iure explicabo dolore voluptas sint alias praesentium illum distinctio laboriosam dolor maxime qui repudiandae voluptas ut quisquam est sequi placeat cumque iste voluptatem animi sint dolores autem ut voluptatem alias perspiciatis ex quos est earum nulla ullam nam alias inventore ex qui dolorem tempora odio voluptatibus consequatur fugiat aut autem est qui qui commodi autem a saepe similique et ipsam saepe qui.', 4882, 292, 4775, 3, 21, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(10, 'adipisci sunt quidem', 'Saepe omnis error magni voluptas consequatur et adipisci ipsum molestiae rerum et voluptatem nobis asperiores qui harum nostrum eveniet numquam magni et eos non optio et iure reprehenderit velit quia aut minima vel et nesciunt occaecati repudiandae exercitationem temporibus non ad omnis enim tenetur dolorem dolor doloremque nihil veniam iure magnam impedit neque aliquam aspernatur dolorem velit autem ut corrupti rerum laboriosam dolor.', 4603, 204, 4745, 21, 16, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(11, 'voluptatum', 'Eos amet magnam aperiam saepe est molestiae et mollitia voluptates quia autem vel vero eum vitae est quia qui eum repellendus et odio impedit corporis dolorem laboriosam temporibus magni nisi ea excepturi assumenda qui consectetur sit magnam aspernatur dolores fuga unde eaque et delectus ducimus dolorum voluptas soluta est praesentium aut tempora dolores ut accusantium explicabo non molestiae perferendis ex dolores dolorem possimus quos earum et.', 1226, 272, 3850, 8, 20, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(12, 'perferendis quisquam', 'Quae maiores dolor consequatur voluptatum voluptatum rerum nulla sit aliquid reiciendis aut sequi accusamus et voluptatem vel dolorem nihil dolor magni provident a aperiam ducimus nemo et molestias cupiditate eum dolorem fugiat laudantium sint vel omnis laudantium qui doloremque minima dolores a asperiores expedita maxime est sint a est consequatur sint minima dicta temporibus nulla qui voluptate quia vitae rerum repellendus expedita sed ut assumenda ullam nobis ut odio consectetur molestias provident soluta provident quisquam quos odit doloribus velit in dolorem sint omnis.', 1269, 233, 1116, 21, 15, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(13, 'dolore aspernatur', 'Velit aut aliquid iure magnam sint atque occaecati ullam et eveniet est beatae et qui cum quae minima temporibus aut omnis libero corporis fugit necessitatibus veritatis rem rem dignissimos aperiam sed qui et nam commodi at veritatis est necessitatibus alias.', 1593, 249, 3056, 5, 15, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(14, 'est', 'Nobis commodi dignissimos velit ut beatae voluptate culpa saepe sequi qui aut voluptatem commodi inventore dolorem cupiditate atque fugit aut qui nam dolor a quibusdam laudantium nostrum placeat est ab necessitatibus voluptatem soluta ut aut incidunt voluptas odio doloribus dolores corporis ut neque atque voluptas quo rerum non dolor qui odit maiores consequatur est voluptatem at tempore velit similique voluptas sequi eos maiores perspiciatis aut et.', 2571, 289, 1487, 17, 22, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(15, 'adipisci animi', 'Molestias rerum id ipsam saepe pariatur omnis eligendi quia eum qui eligendi rerum eius placeat incidunt dolore quidem temporibus voluptatem neque neque in sed ut aspernatur autem at dolore sint totam eos enim quae commodi earum saepe voluptas repudiandae in distinctio quia eum molestiae eum vel harum commodi laboriosam.', 1043, 230, 3082, 11, 15, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(16, 'nihil distinctio', 'Quis laudantium ut rerum est et voluptates voluptate quos perferendis qui voluptatem voluptatem rerum pariatur sint asperiores eius repellendus deleniti aliquam quasi repudiandae enim omnis atque odit illo veniam sunt deleniti cumque necessitatibus praesentium molestiae et dignissimos est est sunt modi voluptatibus sit quis repellat id earum.', 1468, 230, 3626, 11, 21, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(17, 'animi', 'Exercitationem eius ipsum et quisquam deserunt dolores quia aut magnam itaque blanditiis deleniti sapiente consequatur vitae inventore rem impedit quia repellendus voluptate repudiandae officia dolorem et asperiores in perspiciatis inventore quo saepe cum repudiandae et ut dolor aut aut dicta assumenda quia sed officiis omnis illo et dolorum atque soluta et.', 1359, 238, 4496, 20, 21, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(18, 'ipsam consequatur nisi', 'Minus unde dolor culpa quaerat dolorem nemo voluptatum consequatur corrupti laborum molestiae officiis voluptates nisi omnis et ut dolorum repellat qui atque magni eaque esse officia labore non voluptas velit quia qui quibusdam odit consequuntur odio culpa praesentium in mollitia architecto praesentium vero architecto eos qui consequatur qui voluptate facere non consequuntur quidem temporibus rem in nostrum est ratione dolores eveniet et aut esse laboriosam suscipit sed dicta nulla est repellat voluptatem ex nihil nesciunt iusto culpa natus omnis illo voluptate quia magnam deserunt.', 3573, 221, 3451, 17, 15, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(19, 'corrupti culpa sapiente', 'Totam ut repellat veniam sunt vero incidunt earum rerum voluptas quo vel ut unde quis maxime veniam omnis repudiandae nobis dolorem similique in eius minus non voluptatem esse exercitationem ullam nulla nam nulla ut omnis quaerat aut ipsum incidunt neque neque ex ab consequatur voluptas quia dolor repudiandae ratione aut ipsa cupiditate sint odio beatae quidem ut quo sint est minima ipsam officia omnis et quas facilis sit aut minima.', 1399, 231, 4699, 23, 24, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(20, 'possimus ipsam', 'Molestiae expedita sunt voluptatem debitis nam illum odit mollitia possimus quibusdam voluptatem inventore vel aspernatur et excepturi voluptatem dolorem sunt illo alias eum tempora ad in et est delectus nihil sed et amet qui non beatae consequatur repellat provident quae totam saepe eum ratione non dolor voluptas et sed dolor corporis blanditiis dolorem et et iusto voluptatibus recusandae ullam amet eum est illum reprehenderit nulla qui cumque nostrum cum eaque voluptas cumque expedita explicabo sed ullam aut dolore qui ab.', 2306, 295, 1084, 14, 30, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(21, 'modi voluptas ut', 'Qui ipsa nemo dolores possimus omnis recusandae eligendi et expedita est ratione suscipit ea deserunt blanditiis nam suscipit sed sed molestiae possimus quo et modi adipisci eius nulla eligendi explicabo sequi cumque velit eos nemo quo quia tenetur dignissimos autem tenetur nulla quibusdam qui eius ab aut nam doloremque numquam dolor aut.', 3531, 248, 4903, 2, 14, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(22, 'repellendus occaecati aut', 'Maxime ut velit rem porro in repellat quam voluptas veniam in alias accusantium mollitia natus iusto neque nam dolorum ipsum ex qui labore autem quasi reiciendis necessitatibus dolores harum nihil et consequatur et voluptate voluptas aut distinctio dolore vel voluptatem ut dolores labore natus laborum natus blanditiis dignissimos soluta ipsum amet et accusantium sunt numquam dolore mollitia voluptatum qui necessitatibus ducimus sed beatae veritatis rem possimus est fuga ducimus ut pariatur ipsam magni numquam facilis perspiciatis quia modi voluptas et dolorem sint voluptas et molestiae quisquam fugit et similique facere quia rerum et ea et labore enim est rem illum accusamus dolor.', 2833, 252, 1734, 16, 29, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(23, 'possimus', 'Qui minima eligendi voluptas itaque ducimus dolorem animi debitis laboriosam harum porro nesciunt et nemo sapiente est qui aut quis optio in iste qui soluta dolor voluptas quo esse aperiam delectus aspernatur quisquam ullam consectetur illum sunt in esse nesciunt reiciendis aliquam cumque quisquam nisi omnis dolorum nam aliquam eum veritatis fuga et ad pariatur unde ut et tempore dolorem dolore tempora quis voluptas quam corrupti aut laborum illum.', 2236, 294, 3407, 15, 18, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(24, 'debitis cumque et', 'Omnis illo voluptatem et tempore distinctio omnis omnis occaecati ut ab corrupti aperiam non aut quisquam magni iste voluptas rerum aperiam praesentium voluptas velit maxime ut a libero aperiam ea autem quidem dignissimos veritatis aut earum et ea.', 1537, 267, 3891, 10, 18, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(25, 'nihil molestias repellat', 'Neque qui sed nobis mollitia ea velit et veniam sit et similique excepturi suscipit quas soluta est eum mollitia id consequatur et iusto corporis sequi voluptatem unde voluptatibus facilis et aut nisi vero a repellendus non consequuntur quam totam molestias aut ut natus sit ea quo ut iste qui alias ducimus sit unde aut perspiciatis laborum dicta cum quibusdam alias nihil libero accusantium rerum sint neque.', 3273, 225, 4952, 22, 17, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(26, 'et quasi repellat', 'Fugit labore nam sunt voluptatem occaecati minima quis quae et mollitia dignissimos harum alias quia suscipit blanditiis vitae molestiae rerum est quasi illo quibusdam accusamus est eligendi dignissimos quos autem aliquam quasi pariatur esse nihil consequuntur quisquam quaerat perspiciatis autem necessitatibus qui quia velit dolor.', 3697, 274, 3191, 2, 29, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(27, 'vero aut', 'Maiores quia aspernatur ad ex sequi officia ipsam cumque magnam saepe ipsum sint qui mollitia velit quaerat tenetur officiis assumenda nam et culpa quia aperiam debitis et eligendi dolorem sint necessitatibus et voluptatem expedita quod nisi voluptatem totam est rerum.', 2294, 290, 3130, 25, 29, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(28, 'aliquam', 'Aliquid voluptatibus ullam pariatur autem qui voluptas labore hic in qui veniam voluptate et voluptas nulla impedit minus consequatur quas fuga omnis sit fuga et unde eius dignissimos velit ut quia nostrum dolores aliquid quis quia in nihil qui occaecati deleniti asperiores esse nulla nobis nostrum assumenda voluptatem accusamus eum voluptas eum ratione blanditiis mollitia sit eligendi rerum consectetur eaque rerum alias nemo commodi dolores voluptas deleniti unde neque.', 1885, 213, 4896, 18, 23, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(29, 'dicta illo', 'Dolore velit voluptate omnis et corporis totam libero ullam saepe qui enim assumenda molestias eos qui in illum dolor occaecati aut corporis maxime deleniti mollitia rem reprehenderit non ut fugiat laborum quia ut et facilis voluptas facere in odio inventore praesentium est sit hic ab saepe dolorem quidem aut voluptatum culpa et dolorem aut eius eos repellat vero omnis ad rerum incidunt quis ut accusamus omnis sunt eos et eos qui.', 4695, 232, 3735, 7, 23, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(30, 'nisi eos', 'Quo cumque qui cumque consequatur voluptatem debitis facilis in beatae omnis qui ducimus porro esse laboriosam velit doloremque rem assumenda blanditiis et dolor vitae rerum beatae eius reprehenderit sit aut non numquam fugit expedita culpa.', 4763, 273, 2677, 3, 16, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(31, 'nemo', 'Et odit excepturi optio fugiat cum deleniti eligendi est corrupti placeat unde nulla autem architecto ab quibusdam et labore eveniet unde sequi iste perspiciatis aut libero et nulla ratione laborum voluptatem quos autem quos temporibus molestias deleniti praesentium omnis aut mollitia corrupti id nemo eum a harum cumque numquam ut nemo et voluptatem soluta totam non velit inventore soluta maiores doloribus ea earum repudiandae iure.', 3572, 246, 1558, 22, 22, '2026-04-22 10:16:39', '2026-04-22 10:16:39'),
(32, 'molestiae ut sit', 'Autem facilis omnis nostrum porro doloremque dolorem est eum assumenda quia sed error rerum omnis architecto voluptates dolorem et minima et minima nam explicabo voluptas eaque provident quo voluptas iste quasi reprehenderit optio corrupti ullam laudantium non officiis eos et consequuntur in voluptas aut ut iure id numquam ipsum nobis vitae non quis dicta non consequuntur earum voluptas accusantium ea voluptatem consequatur molestiae et impedit velit omnis quam nihil qui ullam quibusdam consequatur consequatur et iure impedit hic voluptatem et.', 1787, 262, 1929, 5, 29, '2026-04-22 10:16:39', '2026-04-22 10:16:39');
